/* ── HOOKS ───────────────────────────────────────────────── */
function useInView(ref, threshold=0.1) {
  const [v,setV] = useState(false);
  useEffect(()=>{
    const o = new IntersectionObserver(([e])=>{ if(e.isIntersecting) setV(true); },{threshold});
    if(ref.current) o.observe(ref.current);
    return ()=>o.disconnect();
  },[]);
  return v;
}



/* ── REVEAL ──────────────────────────────────────────────── */
function Reveal({children,delay=0,dir="up",style={},className=""}) {
  const ref = useRef(null);
  const v = useInView(ref);
  const t = {up:"translateY(50px)",left:"translateX(-50px)",right:"translateX(50px)",none:"none"};
  return (
    <div ref={ref} className={className} style={{
      opacity:v?1:0, transform:v?"none":t[dir],
      transition:`opacity .9s cubic-bezier(.16,1,.3,1) ${delay}ms, transform .9s cubic-bezier(.16,1,.3,1) ${delay}ms`,
      ...style,
    }}>{children}</div>
  );
}

