/* ── LIGHTBOX ────────────────────────────────────────────── */
function Lightbox({items,activeIndex,onClose,onPrev,onNext}) {
  const item = items[activeIndex];
  useEffect(()=>{
    const fn=(e)=>{ if(e.key==="Escape") onClose(); if(e.key==="ArrowLeft") onPrev(); if(e.key==="ArrowRight") onNext(); };
    document.addEventListener("keydown",fn);
    document.body.style.overflow="hidden";
    return()=>{ document.removeEventListener("keydown",fn); document.body.style.overflow=""; };
  },[onClose,onPrev,onNext]);

  return (
    <div onClick={onClose} style={{
      position:"fixed",inset:0,zIndex:1000,
      background:"rgba(8,4,1,.97)",
      display:"flex",alignItems:"center",justifyContent:"center",
      animation:"lbIn .25s ease",
    }}>
      {/* Close */}
      <button onClick={onClose} style={{
        position:"absolute",top:"24px",right:"24px",
        background:"rgba(255,255,255,.07)",border:"1px solid rgba(255,255,255,.12)",
        width:"46px",height:"46px",display:"flex",alignItems:"center",justifyContent:"center",
        cursor:"pointer",color:"#fff",zIndex:10,transition:"all .3s",
      }}
        onMouseEnter={e=>e.currentTarget.style.background="rgba(201,169,110,.25)"}
        onMouseLeave={e=>e.currentTarget.style.background="rgba(255,255,255,.07)"}
      ><Icon name="close" size={18} color="#fff" sw={1.5}/></button>

      {/* Counter */}
      <div style={{position:"absolute",top:"30px",left:"50%",transform:"translateX(-50%)",
        fontFamily:"'Jost',sans-serif",fontSize:"10px",letterSpacing:"4px",
        color:"rgba(255,255,255,.35)",textTransform:"uppercase"}}>
        {activeIndex+1} / {items.length}
      </div>

      {/* Prev */}
      <button onClick={e=>{e.stopPropagation();onPrev();}} style={{
        position:"absolute",left:"20px",top:"50%",transform:"translateY(-50%)",
        background:"rgba(255,255,255,.05)",border:"1px solid rgba(255,255,255,.1)",
        width:"54px",height:"54px",display:"flex",alignItems:"center",justifyContent:"center",
        cursor:"pointer",transition:"all .3s",zIndex:10,
      }}
        onMouseEnter={e=>{e.currentTarget.style.background="rgba(201,169,110,.2)";e.currentTarget.style.borderColor="rgba(201,169,110,.5)";}}
        onMouseLeave={e=>{e.currentTarget.style.background="rgba(255,255,255,.05)";e.currentTarget.style.borderColor="rgba(255,255,255,.1)";}}
      ><Icon name="chevL" size={22} color="#fff" sw={1.5}/></button>

      {/* Next */}
      <button onClick={e=>{e.stopPropagation();onNext();}} style={{
        position:"absolute",right:"20px",top:"50%",transform:"translateY(-50%)",
        background:"rgba(255,255,255,.05)",border:"1px solid rgba(255,255,255,.1)",
        width:"54px",height:"54px",display:"flex",alignItems:"center",justifyContent:"center",
        cursor:"pointer",transition:"all .3s",zIndex:10,
      }}
        onMouseEnter={e=>{e.currentTarget.style.background="rgba(201,169,110,.2)";e.currentTarget.style.borderColor="rgba(201,169,110,.5)";}}
        onMouseLeave={e=>{e.currentTarget.style.background="rgba(255,255,255,.05)";e.currentTarget.style.borderColor="rgba(255,255,255,.1)";}}
      ><Icon name="chevR" size={22} color="#fff" sw={1.5}/></button>

      {/* Image container */}
      <div onClick={e=>e.stopPropagation()} style={{
        maxWidth:"86vw",maxHeight:"84vh",display:"flex",flexDirection:"column",
        animation:"lbImgIn .38s cubic-bezier(.16,1,.3,1)",
      }}>
        <img key={activeIndex} src={item.img} alt={item.title} style={{
          maxWidth:"100%",maxHeight:"70vh",objectFit:"contain",display:"block",
          animation:"lbImgIn .38s cubic-bezier(.16,1,.3,1)",
        }}/>
        {/* Caption + thumbs */}
        <div style={{paddingTop:"18px",marginTop:"16px",borderTop:"1px solid rgba(255,255,255,.08)",
          display:"flex",justifyContent:"space-between",alignItems:"flex-end",gap:"20px"}}>
          <div>
            <div style={{fontFamily:"'Cormorant Garamond',serif",fontSize:"20px",fontWeight:500,color:"#fff"}}>{item.title}</div>
            <div style={{fontFamily:"'Jost',sans-serif",fontSize:"9px",letterSpacing:"3px",color:"rgba(201,169,110,.7)",marginTop:"4px",textTransform:"uppercase"}}>{item.loc}</div>
          </div>
          <div style={{display:"flex",gap:"5px",flexWrap:"wrap",justifyContent:"flex-end"}}>
            {items.map((it,i)=>(
              <div key={i} onClick={e=>{e.stopPropagation();}} style={{
                width:"38px",height:"28px",overflow:"hidden",cursor:"pointer",flexShrink:0,
                outline:i===activeIndex?"2px solid #c9a96e":"2px solid transparent",
                outlineOffset:"1px",opacity:i===activeIndex?1:.4,transition:"opacity .3s,outline .3s",
              }}>
                <img src={it.thumb} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

